"use client";

import { useState, useEffect } from "react";
import {Playfair_Display, DM_Sans} from "next/font/google";

const playfair = Playfair_Display({ subsets: ["latin"], weight: ["400", "600", "700", "900"], variable: "--font-playfair" });
